INSERT INTO `dpia_registrations` (`id`, `record_id`, `description`, `necessity_proportionality`, `mitigation_measures`, `residual_risk`, `overall_risk_level`, `status`, `registered_by`, `registered_at`, `updated_at`, `notes`, `title`, `review_date`, `processing_activity_description`, `risk_origin`, `necessity_test`, `proportionality_test`, `data_subjects_affected`, `data_categories`, `compliance_checklist`, `risk_assessment_matrix`, `consultation_conducted`, `consultation_details`, `recommendations`, `management_approval`, `approved_by`, `approval_date`, `necessity`, `proportionality`) VALUES
(300000003, 200000033, 'DPIA voor betalingsverwerking aan kassa\'s', NULL, 'logging alle transacties, regelmatige audits, inzage in het transactie proces', 'Geen.', 'medium', 'in_progress', 100000006, '2026-02-26 09:48:43', '2026-03-11 08:44:18', '', 'DPIA voor betalingsverwerking aan kassa\'s', '2026-02-26', 'Transactie verwerking fictieve betalingen van supermarkt artikelen. Digitalebon met gekochte artikelen op eigen pasje.', 'other', 'Betalingsverwerking is noodzakelijk voor operatie fictieve geld passen. Verwerking is proportioneel met strikte beveiliging.', 'Minimale gegevens opslag. Deze moet nog verder uitgewerkt worden door te verdiepen in het proces.', 1300, 'Boodschap artikelen. aantallen, product prijs', NULL, NULL, 'no', '', '', 'pending', NULL, NULL, NULL, NULL),
(300000004, 200000028, 'Risico verwerken van de begeleiding van zieke medewerkers en re-integratie medewekers', NULL, 'Aparte medische multimap, strikte toegangscontrole door sleutel op kast, minimale dataverzameling. Zwarte marker notities welke niet vereist zijn te laten  zien', 'Hoog resterend risico door gevoelige aard medische gegevens', 'medium', 'in_progress', 100000006, '2026-02-26 09:58:23', '2026-02-26 09:58:23', '', 'Begeleiding zieke medewerkers en re-integratie', '2026-02-26', 'Begeleiding zieke medewerkers en re-integratie', 'other', 'Verwerking is wettelijk verplicht voor re-integratieplicht bij langdurig ziekteverzuim.', 'Alleen relevante medische gegevens voor re-integratie worden verwerkt. Strikte scheiding medische en HR data.', 150, 'Medische gegevens, verzuimgeschiedenis, re-integratieplan, CAO-protocollen', NULL, NULL, 'no', '', '', 'pending', NULL, NULL, NULL, NULL),
(300000005, 200000014, 'Risisco vewerking van banktransactie donateurs', NULL, 'Schaduw boekhouding proces dient nagegaan te worden of deze pseudonimiseert', 'Hoog risico op datalek bij schaduw administratie', 'medium', 'in_progress', 100000006, '2026-02-26 10:05:47', '2026-02-26 10:05:47', '', 'Donateurregistratie en giftenadministratie', '2026-02-26', 'Donateurregistratie en giftenadministratie', 'other', 'Vewerking van banktransacties is essentieel voor voortbestaan voedselbank almere.', 'Geen exports van banktransacties in csv of andere formaat.', 1200, 'namen en banknummers en banktransacties hoeveelheid in euro', NULL, NULL, 'no', '', '', 'pending', NULL, NULL, NULL, NULL),
(300000006, 200000012, 'Risco op datalek bij externe dienstverleners waar het gaat om het verwerken van voedselbank bezoekers en belangstellende zoals medewekers voor de digitale verzending van niewsbrieven', NULL, 'Geen exports van mailadressen', '.', 'medium', 'in_progress', 100000006, '2026-02-26 10:17:56', '2026-05-05 09:06:05', '', 'Nieuwsbrief en communicatie met belangstellenden', '2026-02-26', 'Nieuwsbrief en communicatie met belangstellenden', 'other', '.', '.', 2500, '.', NULL, NULL, 'no', '', '', 'pending', NULL, NULL, NULL, NULL),
(300000007, 200000011, 'De vewerking van ongeveer 362 huishouden/cliënten (exlusief kinderen) data neemt risicos met zich mee aangaande de avg wetgeving. De wetgeving vereist pseudonimiseren van alle data die persoonsgegevens bevatten. Dat is van toepassing', NULL, 'Multifactor login op Microsoft Access\r\nMeer beveiliging tot rol gescheiden mogelijkheden in Microsoft Access.\r\nHidden paths\r\nvba code en bat file met smoke screen waar de dat toegankelijk is\r\nMogelijkheden om mee te doen met andere software in de markt, denk aan voedselbanken welke het anders doen dan ons. Wat kunnen we daarvan leren en oppakken.\r\nGeen exports van data buiten de Microsoft engine', 'Geen mogelijkheid nog tot pseudonimiseren.\r\nDe engine van Microsoft Access heeft hier nog geen upgrade voor aangeboden. Wij wachten hier op, om de risicos te beperken met data kopieren of een database hack.', 'medium', 'in_progress', 100000006, '2026-03-04 09:32:24', '2026-05-26 09:17:30', '', 'Risco registratie activiteiten cliënten voor voedselhulp', '2026-03-04', 'De verwerking van informatie over cliënten binnen voedselbank almere', 'other', 'Data is noodzakelijk om een intake te maken van welke type cliënten Voedselbank Almere heeft en hoe een oordeel valt over hun situatie m.b.t voedselhulp en meubels en kleding door zowel intake als toetsingscommissie. Hiervoor werken wij samen met intake instanties aan de voorkant van de organisatie denk aan hulpinstanties welke mensen helpen schulderen terug te betalen of leger des heils en overheden zoals lokale gemeenten.', '550 huishoudens waarvan ongeveer 1300 personen (2025)\r\n\r\nDataretentie is dat cliënten ongeveer maximaal 2 jaar mee draaien. Na die twee jaar moeten cliënten eigenlijk wel weer zelfvoorzienend zijn. We verwijderen cliënten zodra ze geen gebruik maken van voedselhulp, als het ware inactieve cliënten. Daarna willen we dat data via Microsoft Access altijd gespeudonimiseerd is. Daarom wachten wij een migratie af naar een nieuwe versie van Microsoft Access on site(niet cloud). Ook hopen wij dat zij werken aan een engine die standaard alle data migreerd naar geroteerde data zodat het bij data lek data niet menselijk leesbaar is zonder de rotering te begrijpen (terug bouwend menselijk lezen). Het alternatief is dat we vooral kijken in de markt wat er beschikbaar is. Helaas is dit niet toepasselijk, omdat live data niet makkelijk te vertalen is een een beschikbaar pakket waar we mee te maken hebben dagelijks. Ook de menselijke aspecten zoals het werken met de tools is daarbij een hindernis. We weten dat het mogelijk is om te gaan pseudonimiseren via VBA code, dat is alleen mogelijk voor bepaalde instructies maar niet voor het geheel. Daarom wachten we op Microsoft voor een complete engine pseudonimiseer tool. Eigenlijk is Microsoft Access compleet met formulieren, sql queries en data filtering de beste optie nog steeds.', 1300, 'Meerdere persoonlijke gegevens over inkomsten uitgaven type cliënten. Denk ook aan schulden of cliënent zijn oorlogsvluchteling of een onderneming in de problemen geraakt door schulden', NULL, '{\"major\":{\"rare\":\"1\"}}', 'no', '', '', 'pending', NULL, NULL, NULL, NULL),
(300000008, 200000027, 'Riscio verwerking van medische gegevens t.b.v. de registratie van ongevallen en bijna-ongevallen', NULL, '.', '.', 'medium', 'in_progress', 100000006, '2026-03-04 10:28:22', '2026-03-04 12:26:01', '.', 'Registratie arbeidsongevallen volgens CAO en Arbowet', '2026-03-04', 'Registratie arbeidsongevallen volgens CAO en Arbowet', 'other', '.', '.', 10, 'interne medewerkers (vrijwiliggers)', NULL, '{\"catastrophic\":{\"rare\":\"1\"}}', 'planned', '.', '.', 'pending', NULL, NULL, NULL, NULL),
(300000010, 200000038, '@lliCash Pasuitgifte en clientadministratie van de saldo op de passen', NULL, '@lliCash', '@lliCash', 'medium', 'draft', 100000006, '2026-06-02 08:31:00', '2026-06-02 08:36:18', '', '@lliCash', NULL, '@lliCash', 'sensitive_data', '@lliCash', '@lliCash', 0, '@lliCash', NULL, NULL, 'no', '', '', 'pending', NULL, NULL, NULL, NULL);

